parameters.query:
DO $$
DECLARE
  v_mov INTEGER;
  v_con INTEGER;
  v_mem INTEGER;
BEGIN
  DELETE FROM movimentacoes;
  GET DIAGNOSTICS v_mov = ROW_COUNT;

  DELETE FROM contas;
  GET DIAGNOSTICS v_con = ROW_COUNT;

  DELETE FROM n8n_chat_histories;
  GET DIAGNOSTICS v_mem = ROW_COUNT;

  RAISE NOTICE 'Limpeza concluída: % movimentações, % contas, % mensagens de memória removidas', v_mov, v_con, v_mem;
END;
$$;
